def make_user(name: str, roles: list[str]) -> dict[str, object]:
    # A typed factory: annotations document the contract and tools can check it.
    return {"name": name, "roles": list(roles)}

tests.content:
import typing

from solution import make_user


def test_returns_expected_value():
    u = make_user("ann", ["admin", "qa"])
    assert u == {"name": "ann", "roles": ["admin", "qa"]}


def test_roles_is_copied_not_aliased():
    src = ["qa"]
    u = make_user("bob", src)
    src.append("admin")
    assert u["roles"] == ["qa"], "the factory must not alias the caller's list"


def test_annotations_use_builtin_generics():
    hints = typing.get_type_hints(make_user)
    assert hints["name"] is str
    assert hints["roles"] == list[str], "roles must be annotated list[str]"
    assert hints["return"] == dict[str, object], "return must be dict[str, object]"


def test_get_type_hints_has_no_return_leftover_for_params():
    hints = typing.get_type_hints(make_user)
    assert set(hints) == {"name", "roles", "return"}

