from typing import TypedDict


class Case(TypedDict):
    name: str
    expected: int
    timeout: int | None


def make_case(name: str, expected: int, timeout: int | None = None) -> Case:
    # Build a TypedDict value. At runtime a TypedDict is a plain dict, so this
    # is just a dict literal whose shape is documented by Case.
    return {"name": name, "expected": expected, "timeout": timeout}

tests.content:
import typing

from solution import Case, make_case


def test_builds_a_plain_dict():
    c = make_case("login", 200, 5)
    assert c == {"name": "login", "expected": 200, "timeout": 5}
    assert isinstance(c, dict), "a TypedDict value is a plain dict at runtime"


def test_timeout_defaults_to_none():
    c = make_case("logout", 204)
    assert c["timeout"] is None


def test_typeddict_field_types():
    hints = typing.get_type_hints(Case)
    assert hints["name"] is str
    assert hints["expected"] is int
    assert hints["timeout"] == typing.Optional[int], "timeout must be int | None"


def test_is_a_typeddict_not_a_dataclass():
    # Tricky: TypedDict carries __required_keys__; it is NOT a class you
    # instantiate with Case(...) attribute access.
    assert hasattr(Case, "__required_keys__")
    assert set(Case.__required_keys__) == {"name", "expected", "timeout"}


def test_function_return_is_case():
    hints = typing.get_type_hints(make_case)
    assert hints["return"] is Case

