from typing import Protocol, runtime_checkable


@runtime_checkable
class Notifier(Protocol):
    # Structural contract: anything with a send(message) -> bool method
    # satisfies Notifier, no inheritance required.
    def send(self, message: str) -> bool: ...


def broadcast(notifier: Notifier, messages: list[str]) -> int:
    # Send each message; count how many were accepted (returned truthy).
    if not isinstance(notifier, Notifier):
        raise TypeError("notifier must implement send(message) -> bool")
    sent = 0
    for message in messages:
        if notifier.send(message):
            sent += 1
    return sent

tests.content:
import pytest

from solution import Notifier, broadcast


class FakeNotifier:
    # A structural test double: no inheritance from Notifier, just the method.
    def __init__(self, accept=True):
        self.accept = accept
        self.calls = []

    def send(self, message):
        self.calls.append(message)
        return self.accept


def test_is_runtime_checkable():
    fake = FakeNotifier()
    assert isinstance(fake, Notifier), "a structural double must satisfy the Protocol"


def test_counts_accepted_messages():
    fake = FakeNotifier(accept=True)
    assert broadcast(fake, ["a", "b", "c"]) == 3
    assert fake.calls == ["a", "b", "c"]


def test_rejected_messages_not_counted():
    fake = FakeNotifier(accept=False)
    assert broadcast(fake, ["a", "b"]) == 0


def test_object_without_send_is_rejected():
    # Tricky: an object missing the method does NOT satisfy the Protocol and
    # broadcast must reject it rather than blow up with AttributeError.
    class NotANotifier:
        def ping(self, message):
            return True

    assert not isinstance(NotANotifier(), Notifier)
    with pytest.raises(TypeError):
        broadcast(NotANotifier(), ["x"])


def test_empty_messages():
    assert broadcast(FakeNotifier(), []) == 0

