from __future__ import annotations

import typing
from typing import Callable


def required_fixtures(func: Callable[..., object]) -> dict[str, type]:
    # Inspect a function's parameter annotations and return the resolved type
    # each parameter expects, ignoring the return annotation. Forward-reference
    # strings (created by `from __future__ import annotations`) must be
    # resolved to real types via typing.get_type_hints, not left as strings.
    hints = typing.get_type_hints(func)
    return {name: hint for name, hint in hints.items() if name != "return"}


def check_wiring(func: Callable[..., object], provided: dict[str, object]) -> list[str]:
    # Compare the values a caller plans to pass against the function's declared
    # parameter types. Return a sorted list of parameter names whose provided
    # value is of the wrong type (a wiring bug a typed fixture would catch).
    expected = required_fixtures(func)
    wrong = []
    for name, typ in expected.items():
        if name in provided and not isinstance(provided[name], typ):
            wrong.append(name)
    return sorted(wrong)

tests.content:
from __future__ import annotations

from solution import check_wiring, required_fixtures


def handler(name: str, retries: int, enabled: bool) -> dict:
    return {"name": name, "retries": retries, "enabled": enabled}


def test_resolves_string_annotations_to_real_types():
    # Tricky: with `from __future__ import annotations` the raw __annotations__
    # are strings like "str". get_type_hints must resolve them to real types.
    fixtures = required_fixtures(handler)
    assert fixtures == {"name": str, "retries": int, "enabled": bool}
    assert all(isinstance(t, type) for t in fixtures.values()), "annotations must be resolved, not left as strings"


def test_return_annotation_excluded():
    assert "return" not in required_fixtures(handler)


def test_correct_wiring_reports_no_errors():
    provided = {"name": "login", "retries": 3, "enabled": True}
    assert check_wiring(handler, provided) == []


def test_detects_type_mismatch():
    provided = {"name": "login", "retries": "3", "enabled": True}
    assert check_wiring(handler, provided) == ["retries"]


def test_multiple_mismatches_sorted():
    provided = {"name": 1, "retries": "x", "enabled": True}
    assert check_wiring(handler, provided) == ["name", "retries"]


def test_bool_is_not_accepted_for_int_param():
    # Edge: bool is a subclass of int, so isinstance(True, int) is True.
    # A True passed where int is expected is therefore NOT flagged. Document
    # this real-world subtlety rather than fight it.
    provided = {"retries": True}
    assert check_wiring(handler, provided) == []


def test_missing_keys_are_ignored():
    # Only checks the keys actually provided; absent fixtures aren't errors here.
    assert check_wiring(handler, {}) == []
